import string
import matplotlib.pyplot as plt

def task_func(s):
    if not isinstance(s, str):
        raise ValueError("Input must be a string.")

    letter_freq = {}
    for char in s:
        if char in string.ascii_lowercase + string.ascii_uppercase:
            letter_freq[char] = letter_freq.get(char, 0) + 1

    max_frequency = max(letter_freq.values())
    normalized_freq = {letter: freq / max_frequency for letter, freq in letter_freq.items()}

    fig, ax = plt.subplots()
    ax.bar(list(normalized_freq.keys()), list(normalized_freq.values()))
    ax.set_xlabel('Letters')
    ax.set_ylabel('Frequency')
    ax.set_title('Letter Frequencies')
    plt.tight_layout()

    return normalized_freq, ax
